from openai import OpenAI
import json

client = OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "Return current weather for a city.",
            "parameters": {
                "type": "object",
                "properties": {
                    "city":  {"type": "string", "description": "City name"},
                    "units": {"type": "string", "enum": ["celsius", "fahrenheit"]}
                },
                "required": ["city"]
            }
        }
    }
]

def get_weather(city: str, units: str = "celsius") -> dict:
    return {"city": city, "temperature": 22, "units": units, "condition": "Partly cloudy"}

response = client.chat.completions.create(
    model="llama3.1:8b-instruct",
    messages=[{"role": "user", "content": "What's the weather in Berlin?"}],
    tools=TOOLS
)

msg = response.choices[0].message
if msg.tool_calls:
    for tc in msg.tool_calls:
        args = json.loads(tc.function.arguments)
        print(f"Calling {tc.function.name}({args})")
        result = get_weather(**args)
        print(f"Result: {result}")

from openai import OpenAI
import json

client = OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")

TOOLS = [
    {"type": "function", "function": {
        "name": "calculate",
        "description": "Evaluate a simple arithmetic expression.",
        "parameters": {
            "type": "object",
            "properties": {"expression": {"type": "string"}},
            "required": ["expression"]
        }
    }},
    {"type": "function", "function": {
        "name": "get_capital",
        "description": "Return the capital city of a country.",
        "parameters": {
            "type": "object",
            "properties": {"country": {"type": "string"}},
            "required": ["country"]
        }
    }}
]

def calculate(expression: str) -> str:
    try:
        return str(eval(expression, {"__builtins__": {}}))
    except Exception as e:
        return f"Error: {e}"

def get_capital(country: str) -> str:
    capitals = {"France": "Paris", "Japan": "Tokyo", "Germany": "Berlin"}
    return capitals.get(country, f"Unknown capital for {country}")

HANDLERS = {"calculate": calculate, "get_capital": get_capital}

messages = [{"role": "user", "content": "What is 144 * 7, and what is the capital of Japan?"}]

MAX_TURNS = 8
for _ in range(MAX_TURNS):
    response = client.chat.completions.create(
        model="llama3.1:8b-instruct",
        messages=messages,
        tools=TOOLS
    )
    choice = response.choices[0]
    messages.append(choice.message)   # append AssistantMessage object

    if choice.finish_reason == "stop":
        print(choice.message.content)
        break

    for tc in (choice.message.tool_calls or []):
        args = json.loads(tc.function.arguments)
        result = HANDLERS[tc.function.name](**args)
        messages.append({
            "role":         "tool",
            "tool_call_id": tc.id,
            "content":      json.dumps({"result": result})
        })

from openai import OpenAI
from pydantic import BaseModel, ValidationError
import json

client = OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")

class WeatherArgs(BaseModel):
    city: str
    units: str = "celsius"

def safe_get_weather(raw_args: str) -> dict:
    try:
        parsed = json.loads(raw_args)
        args = WeatherArgs(**parsed)
    except (json.JSONDecodeError, ValidationError) as e:
        return {"error": f"Bad args: {e}"}

    # Proceed only with validated args
    return {"city": args.city, "temperature": 19, "units": args.units}

TOOL = [{"type": "function", "function": {
    "name": "get_weather",
    "description": "Get weather for a city.",
    "parameters": {
        "type": "object",
        "properties": {
            "city":  {"type": "string"},
            "units": {"type": "string", "enum": ["celsius", "fahrenheit"]}
        },
        "required": ["city"]
    }
}}]

response = client.chat.completions.create(
    model="llama3.1:8b-instruct",
    messages=[{"role": "user", "content": "Weather in Vienna?"}],
    tools=TOOL
)

msg = response.choices[0].message
if msg.tool_calls:
    for tc in msg.tool_calls:
        result = safe_get_weather(tc.function.arguments)
        print(json.dumps(result, indent=2))

