from openai import OpenAI
import json, time
from dataclasses import dataclass, field

client = OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")

@dataclass
class LoopMetrics:
    inference_ms: list[float] = field(default_factory=list)
    tool_exec_ms: list[float] = field(default_factory=list)

    def avg_inference(self) -> float:
        return sum(self.inference_ms) / len(self.inference_ms) if self.inference_ms else 0.0

    def avg_tool_exec(self) -> float:
        return sum(self.tool_exec_ms) / len(self.tool_exec_ms) if self.tool_exec_ms else 0.0

    def report(self) -> str:
        return (
            f"Inference calls: {len(self.inference_ms)} | "
            f"Avg inference: {self.avg_inference():.0f}ms | "
            f"Tool calls: {len(self.tool_exec_ms)} | "
            f"Avg tool exec: {self.avg_tool_exec():.0f}ms"
        )

def slow_add(a: float, b: float) -> dict:
    time.sleep(0.01)   # simulate I/O
    return {"sum": a + b}

TOOL = [{"type": "function", "function": {
    "name": "slow_add",
    "description": "Add two numbers.",
    "parameters": {
        "type": "object",
        "properties": {"a": {"type": "number"}, "b": {"type": "number"}},
        "required": ["a", "b"]
    }
}}]

metrics = LoopMetrics()
messages = [{"role": "user", "content": "What is 55 plus 89?"}]

for _ in range(8):
    t0 = time.monotonic()
    response = client.chat.completions.create(
        model="llama3.1:8b-instruct", messages=messages, tools=TOOL
    )
    metrics.inference_ms.append((time.monotonic() - t0) * 1000)

    choice = response.choices[0]
    messages.append(choice.message)

    if choice.finish_reason == "stop":
        print(choice.message.content)
        break

    for tc in (choice.message.tool_calls or []):
        args = json.loads(tc.function.arguments)
        t1 = time.monotonic()
        result = slow_add(**args)
        metrics.tool_exec_ms.append((time.monotonic() - t1) * 1000)
        messages.append({
            "role": "tool", "tool_call_id": tc.id,
            "content": json.dumps(result)
        })

print(metrics.report())
